import re
from typing import Callable
from langchain_core.documents import Document

# Simple heuristic activators — replace with an LLM classifier for production
def needs_sql(question: str) -> bool:
    patterns = [r"\bhow many\b", r"\bcount\b", r"\btotal\b", r"\bsum\b", r"\blast \d+ (days?|weeks?|months?)\b"]
    return any(re.search(p, question, re.IGNORECASE) for p in patterns)

def needs_web(question: str) -> bool:
    patterns = [r"\btoday\b", r"\bcurrent\b", r"\blatest\b", r"\brecent\b", r"\bnews\b"]
    return any(re.search(p, question, re.IGNORECASE) for p in patterns)


async def selective_multi_source_retrieve(question: str) -> list[Document]:
    tasks = [fetch_vector(question), fetch_bm25(question)]

    if needs_sql(question):
        tasks.append(fetch_sql(question))
    if needs_web(question):
        tasks.append(fetch_web(question))

    result_lists = await asyncio.gather(*tasks)
    merged = reciprocal_rank_fusion(list(result_lists), top_n=8)
    return dedup_documents(merged, max_docs=6)


