from collections import Counter


def source_contribution_report(
    questions: list[str],
    retriever_fn,
    top_n: int = 5,
) -> dict[str, float]:
    """
    Run retriever_fn on each question, count how often each source
    appears in the top_n results, and return a fraction per source.
    """
    source_counts: Counter = Counter()
    total_slots = 0

    for question in questions:
        docs = retriever_fn(question)[:top_n]
        for doc in docs:
            source = doc.metadata.get("source", "unknown")
            source_counts[source] += 1
        total_slots += len(docs)

    return {
        source: round(count / total_slots * 100, 1)
        for source, count in source_counts.most_common()
    }


